         role="button" @onclick="() => _expanded = !_expanded">
        <h6 class="mb-0">Change Password</h6>
        <span class="@(_expanded ? "rotate-icon" : "")">▶</span>
    </div>

    @if (_expanded)
    {
        <div class="card-body">
