@code {
    [Parameter, EditorRequired]
    public ISettingsService SettingsService { get; set; } = default!;

    private bool _expanded;
    private string _currentPassword = "";
    private string _newPassword = "";
    private string _confirmPassword = "";
    private bool _saving;
    private string? _message;
    private bool _isError;

    private string? NewPasswordError =>
        _newPassword.Length > 0 && _newPassword.Length < 8 ? "Password must be at least 8 characters." : null;

    private string? ConfirmError =>
        _confirmPassword.Length > 0 && _confirmPassword != _newPassword ? "Passwords do not match." : null;

    private async Task UpdatePasswordAsync()
    {
        _message = null;

        if (string.IsNullOrWhiteSpace(_currentPassword) || string.IsNullOrWhiteSpace(_newPassword))
        {
            _message = "Please fill in all password fields.";
            _isError = true;
            return;
        }

        if (NewPasswordError is not null || ConfirmError is not null)
            return;

        _saving = true;
        try
        {
            await SettingsService.ChangePasswordAsync(_currentPassword, _newPassword);
            _message = "Password updated successfully!";
            _isError = false;
            _currentPassword = "";
            _newPassword = "";
            _confirmPassword = "";
        }
        catch (Exception ex)
        {
            _message = $"Failed to update password: {ex.Message}";
            _isError = true;
        }
        finally
        {
            _saving = false;
        }
    }
}

.card-header .rotate-icon {
    display: inline-block;
    transform: rotate(90deg);
    transition: transform 0.2s;
}

@using sv_c46633faca484977b26158d7cf773357.Services

<div class="card mb-3">
    <div class="card-body">
        <h6 class="card-title mb-3">Active Sessions</h6>

        @if (Sessions is null || Sessions.Count == 0)
        {
            <p class="text-muted">No active sessions.</p>
        }
        else
        {
            <div class="table-responsive">
                <table class="table table-hover align-middle mb-0">
                    <thead>
                        <tr>
                            <th>Device</th>
                            <th>Location</th>
                            <th>Last Active</th>
                            <th class="text-end">Action</th>
                        </tr>
                    </thead>
                    <tbody>
                        @foreach (var session in Sessions)
                        {
                            var isCurrent = session.Id == CurrentSessionId;
                            <tr>
                                <td>
                                    @session.Device
                                    @if (isCurrent)
                                    {
                                        <span class="badge bg-success ms-1">Current</span>
                                    }
                                </td>
                                <td>@session.Location</td>
                                <td>@session.LastActive.ToString("g")</td>
                                <td class="text-end">
                                    @if (!isCurrent)
                                    {
                                        <button class="btn btn-outline-danger btn-sm"
                                                @onclick="() => PromptRevoke(session)"
                                                disabled="@(_revoking == session.Id)">
                                            @if (_revoking == session.Id)
                                            {
                                                <span class="spinner-border spinner-border-sm" role="status"></span>
                                            }
                                            else
                                            {
                                                <span>Revoke</span>
                                            }
                                        </button>
                                    }
                                </td>
                            </tr>
                        }
                    </tbody>
                </table>
            </div>
        }
    </div>
</div>

@* Revoke confirmation dialog *@
@if (_sessionToRevoke is not null)
{
    <div class="modal-backdrop fade show"></div>
    <div class="modal d-block fade show" tabindex="-1" role="dialog">
        <div class="modal-dialog modal-dialog-centered" role="document">
            <div class="modal-content">
                <div class="modal-header">
                    <h5 class="modal-title">Revoke Session</h5>
                    <button type="button" class="btn-close" @onclick="CancelRevoke"></button>
                </div>
                <div class="modal-body">
                    <p>Are you sure you want to revoke the session on <strong>@_sessionToRevoke.Device</strong> from <strong>@_sessionToRevoke.Location</strong>?</p>
                    <p class="text-muted small mb-0">This will sign out that device immediately.</p>
                </div>
                <div class="modal-footer">
                    <button type="button" class="btn btn-secondary" @onclick="CancelRevoke">Cancel</button>
                    <button type="button" class="btn btn-danger" @onclick="ConfirmRevokeAsync">Revoke</button>
                </div>
            </div>
        </div>
    </div>
}

@code {
    [Parameter, EditorRequired]
    public List<ActiveSession> Sessions { get; set; } = [];

    [Parameter]
    public string? CurrentSessionId { get; set; }

    [Parameter, EditorRequired]
    public EventCallback<string> OnSessionRevoked { get; set; }

    private ActiveSession? _sessionToRevoke;
    private string? _revoking;

    private void PromptRevoke(ActiveSession session)
    {
        _sessionToRevoke = session;
    }

    private void CancelRevoke()
    {
        _sessionToRevoke = null;
    }

    private async Task ConfirmRevokeAsync()
    {
        if (_sessionToRevoke is null) return;

        var sessionId = _sessionToRevoke.Id;
        _sessionToRevoke = null;
        _revoking = sessionId;

        await OnSessionRevoked.InvokeAsync(sessionId);

        _revoking = null;
    }
}

