toolArgs.file_text:
@using sv_c46633faca484977b26158d7cf773357.Services

<div class="card mb-3">
    <div class="card-header d-flex align-items-center justify-content-between"
         role="button" @onclick="() => _expanded = !_expanded">
        <h6 class="mb-0">Change Password</h6>
        <span class="@(_expanded ? "rotate-icon" : "")">▶</span>
    </div>

    @if (_expanded)
    {
        <div class="card-body">
            @if (_message is not null)
            {
                <div class="alert @(_isError ? "alert-danger" : "alert-success") alert-dismissible fade show" role="alert">
                    @_message
                    <button type="button" class="btn-close" @onclick="() => _message = null"></button>
                </div>
            }

            <div class="mb-3">
                <label class="form-label">Current Password</label>
                <input type="password" class="form-control" @bind="_currentPassword" />
            </div>

            <div class="mb-3">
                <label class="form-label">New Password</label>
                <input type="password" class="form-control @(NewPasswordError is not null ? "is-invalid" : "")" @bind="_newPassword" />
                @if (NewPasswordError is not null)
                {
                    <div class="invalid-feedback">@NewPasswordError</div>
                }
            </div>

            <div class="mb-3">
                <label class="form-label">Confirm New Password</label>
                <input type="password" class="form-control @(ConfirmError is not null ? "is-invalid" : "")" @bind="_confirmPassword" />
                @if (ConfirmError is not null)
                {
                    <div class="invalid-feedback">@ConfirmError</div>
                }
            </div>

            <button class="btn btn-warning" @onclick="UpdatePasswordAsync" disabled="@_saving">
                @if (_saving)
                {
                    <span class="spinner-border spinner-border-sm me-1" role="status"></span>
                }
                Update Password
            </button>
        </div>
    }
</div>

@code {
    [Parameter, EditorRequired]
    public ISettingsService SettingsService { get; set; } = default!;

    private bool _expanded;
    private string _currentPassword = "";
    private string _newPassword = "";
    private string _confirmPassword = "";
    private bool _saving;
    private string? _message;
    private bool _isError;

    private string? NewPasswordError =>
        _newPassword.Length > 0 && _newPassword.Length < 8 ? "Password must be at least 8 characters." : null;

    private string? ConfirmError =>
        _confirmPassword.Length > 0 && _confirmPassword != _newPassword ? "Passwords do not match." : null;

    private async Task UpdatePasswordAsync()
    {
        _message = null;

        if (string.IsNullOrWhiteSpace(_currentPassword) || string.IsNullOrWhiteSpace(_newPassword))
        {
            _message = "Please fill in all password fields.";
            _isError = true;
            return;
        }

        if (NewPasswordError is not null || ConfirmError is not null)
            return;

        _saving = true;
        try
        {
            await SettingsService.ChangePasswordAsync(_currentPassword, _newPassword);
            _message = "Password updated successfully!";
            _isError = false;
            _currentPassword = "";
            _newPassword = "";
            _confirmPassword = "";
        }
        catch (Exception ex)
        {
            _message = $"Failed to update password: {ex.Message}";
            _isError = true;
        }
        finally
        {
            _saving = false;
        }
    }
}

