@code {
    [Parameter, EditorRequired]
    public List<ActiveSession> Sessions { get; set; } = [];

    [Parameter]
    public string? CurrentSessionId { get; set; }

    [Parameter, EditorRequired]
    public EventCallback<string> OnSessionRevoked { get; set; }

    private ActiveSession? _sessionToRevoke;
    private string? _revoking;

    private void PromptRevoke(ActiveSession session)
    {
        _sessionToRevoke = session;
    }

    private void CancelRevoke()
    {
        _sessionToRevoke = null;
    }

    private async Task ConfirmRevokeAsync()
    {
        if (_sessionToRevoke is null) return;

        var sessionId = _sessionToRevoke.Id;
        _sessionToRevoke = null;
        _revoking = sessionId;

        await OnSessionRevoked.InvokeAsync(sessionId);

        _revoking = null;
    }
}

