@using sv_c46633faca484977b26158d7cf773357.Services
@inject ISettingsService SettingsService

<div class="security-section">
    @if (_loading)
    {
        <div class="d-flex justify-content-center p-5">
            <div class="spinner-border" role="status">
                <span class="visually-hidden">Loading...</span>
            </div>
        </div>
    }
    else if (_settings is not null)
    {
        <h4 class="mb-4">Security Settings</h4>

        @if (_message is not null)
        {
            <div class="alert @(_isError ? "alert-danger" : "alert-success") alert-dismissible fade show" role="alert">
                @_message
                <button type="button" class="btn-close" @onclick="() => _message = null"></button>
            </div>
        }

        <ChangePasswordPanel SettingsService="SettingsService" />

        <div class="card mb-3">
            <div class="card-body d-flex align-items-center justify-content-between">
                <div>
                    <h6 class="mb-1">Two-Factor Authentication</h6>
                    <span class="badge @(_settings.TwoFactorEnabled ? "bg-success" : "bg-secondary")">
                        @(_settings.TwoFactorEnabled ? "Enabled" : "Disabled")
                    </span>
                    @if (_settings.LastPasswordChange.HasValue)
                    {
                        <small class="text-muted d-block mt-1">
                            Last password change: @_settings.LastPasswordChange.Value.ToString("d")
                        </small>
                    }
                </div>
                <div class="form-check form-switch">
                    <input class="form-check-input" type="checkbox" id="twoFactor"
                           checked="@_settings.TwoFactorEnabled" disabled
                           title="Contact support to change 2FA settings" />
                </div>
            </div>
        </div>

        <ActiveSessionsTable Sessions="_settings.Sessions"
                             CurrentSessionId="@_settings.Sessions.FirstOrDefault()?.Id"
                             OnSessionRevoked="RevokeSessionAsync" />
    }
</div>

@code {
    private SecuritySettings? _settings;
    private bool _loading = true;
    private string? _message;
    private bool _isError;

    protected override async Task OnInitializedAsync()
    {
        _loading = true;
        _settings = await SettingsService.GetSecuritySettingsAsync();
        _loading = false;
    }

    private async Task RevokeSessionAsync(string sessionId)
    {
        _message = null;
        try
        {
            await SettingsService.RevokeSessionAsync(sessionId);
            _settings = await SettingsService.GetSecuritySettingsAsync();
            _message = "Session revoked successfully.";
            _isError = false;
        }
        catch (Exception ex)
        {
            _message = $"Failed to revoke session: {ex.Message}";
            _isError = true;
        }
    }
}

