@page "/settings"
@rendermode InteractiveServer

<PageTitle>Settings</PageTitle>

<h3 class="mb-4">Settings</h3>

<div class="d-flex settings-layout">
    <SettingsSidebar ActiveSection="@_activeSection" OnSectionChanged="section => _activeSection = section" />

    <div class="flex-grow-1 ps-4 settings-content">
        @switch (_activeSection)
        {
            case "Profile":
                <ProfileSection />
                break;
            case "Notifications":
                <NotificationsSection />
                break;
            case "Security":
                <SecuritySection />
                break;
            case "Appearance":
                <AppearanceSection />
                break;
        }
    </div>
</div>

@code {
    private string _activeSection = "Profile";
}

